package javapackage;

public class ArithmaticOperator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
      int a = 10;
      int b = 5;
      
      System.out.println(a+b); //15
      System.out.println(a-b); //10
      System.out.println(a*b);//50
      System.out.println(a/b); //2
      
      
      
	}

}
